#!/usr/bin/env python3
"""
Multi-Agent Tax-Research System (LangGraph) — single-file project bundle.

Open in VS Code and run once to unpack the full repo, then work normally:
    python agent_research_bundle.py            # -> ./agent-research
    python agent_research_bundle.py my-folder

After unpacking:
    cd agent-research
    pip install -r requirements.txt
    cp .env.example .env   # add ANTHROPIC / OPENAI / TAVILY keys
    python -m unittest discover tests          # offline, no keys needed
    python run.py "What are the 2026 401(k) limits and what changed?"
"""
import base64, sys
from pathlib import Path

FILES = {
 ".env.example": "",
 "README.md": "",
 "config.py": "",
 "requirements.txt": "bGFuZ2dyYXBoPj0wLjIuNDAKbGFuZ2NoYWluLWNvcmU+PTAuMwpsYW5nY2hhaW4tYW50aHJvcGljPj0wLjIKbGFuZ2NoYWluLW9wZW5haT49MC4yCnRhdmlseS1weXRob24+PTAuNQpweXRob24tZG90ZW52Pj0xLjAK",
 "run.py": "",
 "src/__init__.py": "",
 "src/agents/__init__.py": "",
 "src/agents/common.py": "",
 "src/agents/jsonutil.py": "",
 "src/agents/nodes.py": "",
 "src/agents/prompts.py": "",
 "src/graph.py": "",
 "src/models_factory.py": "",
 "src/state.py": "",
 "src/tools/__init__.py": "",
 "src/tools/knowledge_tool.py": "",
 "src/tools/tavily_search.py": "",
 "tests/__init__.py": "",
 "tests/test_config_and_state.py": "",
}


def main():
    target = Path(sys.argv[1]) if len(sys.argv)>1 else Path("agent-research")
    target.mkdir(parents=True, exist_ok=True)
    n=0
    for rel,b64 in FILES.items():
        d=target/rel; d.parent.mkdir(parents=True,exist_ok=True)
        d.write_bytes(base64.b64decode(b64)); n+=1
    print(f"Unpacked {n} files into {target.resolve()}")
    print("Next: cd", target, "&& pip install -r requirements.txt && python -m unittest discover tests")

if __name__=="__main__":
    main()
